return [{
  json: {
    tenantId: 'YOUR_TENANT_ID',
    clientId: 'YOUR_CLIENT_ID',
    clientSecret: 'YOUR_CLIENT_SECRET',
    sharepointFolderUrl: 'https://contoso.sharepoint.com/sites/Finance/Shared%20Documents/Reports',
    downloadRoot: 'C:/n8n/sharepoint-downloads',
    deltaPageSize: 200,
  },
}];

const config = $('Config').first().json;

const required = ['tenantId', 'clientId', 'clientSecret', 'sharepointFolderUrl', 'downloadRoot'];
for (const key of required) {
  const value = String(config[key] ?? '').trim();
  if (!value || value.startsWith('YOUR_')) {
    throw new Error('Set ' + key + ' in the Config node before running the workflow.');
  }
}

let inputUrl;
try {
  inputUrl = new URL(String(config.sharepointFolderUrl).trim());
} catch {
  throw new Error('sharepointFolderUrl is not a valid URL.');
}

const hostname = inputUrl.hostname;
let serverRelativePath = '';
for (const key of ['id', 'RootFolder']) {
  const value = inputUrl.searchParams.get(key);
  if (value) {
    serverRelativePath = decodeURIComponent(value);
    break;
  }
}

if (!serverRelativePath) {
  serverRelativePath = decodeURIComponent(inputUrl.pathname);
}

serverRelativePath = serverRelativePath
  .replace(/\\/g, '/')
  .replace(/\/Forms\/AllItems\.aspx$/i, '')
  .replace(/\/+/g, '/')
  .replace(/\/$/, '');

if (!serverRelativePath.startsWith('/')) {
  serverRelativePath = '/' + serverRelativePath;
}

const segments = serverRelativePath.split('/').filter(Boolean);
if (!segments.length) {
  throw new Error('Could not determine the SharePoint folder path from sharepointFolderUrl.');
}

const candidates = [];
const seen = new Set();

const addCandidate = (siteParts, withinSite) => {
  if (!withinSite.length) return;

  const libraryName = decodeURIComponent(withinSite[0]);
  const folderRelativePath = withinSite.slice(1)
    .map((segment) => decodeURIComponent(segment))
    .join('/');
  const candidateSitePath = siteParts.length ? '/' + siteParts.join('/') : '';
  const siteResolveUrl = candidateSitePath
    ? 'https://graph.microsoft.com/v1.0/sites/' + hostname + ':' + candidateSitePath
    : 'https://graph.microsoft.com/v1.0/sites/' + hostname;

  const candidateKey = candidateSitePath + '|' + libraryName + '|' + folderRelativePath;
  if (seen.has(candidateKey)) return;
  seen.add(candidateKey);

  candidates.push({
    hostname,
    originalUrl: String(config.sharepointFolderUrl).trim(),
    serverRelativePath,
    candidateSitePath,
    siteResolveUrl,
    libraryName,
    folderRelativePath,
  });
};

if (segments[0] === 'sites' || segments[0] === 'teams') {
  if (segments.length < 3) {
    throw new Error('The SharePoint URL must include a site path and a document library.');
  }

  for (let siteLength = segments.length - 1; siteLength >= 2; siteLength--) {
    addCandidate(segments.slice(0, siteLength), segments.slice(siteLength));
  }
} else {
  addCandidate([], segments);
}

if (!candidates.length) {
  throw new Error('No candidate SharePoint site paths could be built from sharepointFolderUrl.');
}

return candidates.map((candidate) => ({ json: candidate }));

const responses = $input.all();

for (let index = 0; index < responses.length; index++) {
  const response = responses[index].json;
  if (response.statusCode >= 200 && response.statusCode < 300 && response.body && response.body.id) {
    const candidate = $('Parse SharePoint URL').itemMatching(index).json;
    return [{
      json: {
        ...candidate,
        siteId: response.body.id,
        siteName: response.body.displayName || response.body.name || '',
        siteWebUrl: response.body.webUrl || '',
      },
    }];
  }
}

throw new Error('None of the candidate SharePoint site paths resolved. Check the URL and confirm the app has Sites.Read.All or Files.Read.All application permissions.');

const site = $('Select Resolved Site').first().json;
const payload = $input.first().json;
const drives = Array.isArray(payload.value) ? payload.value : [];

if (!drives.length) {
  throw new Error('No document libraries were returned for the resolved SharePoint site.');
}

const normalize = (value = '') => decodeURIComponent(String(value))
  .replace(/%20/gi, ' ')
  .toLowerCase()
  .replace(/\s+/g, ' ')
  .trim();

const targetLibrary = normalize(site.libraryName);
const serverRelativePath = normalize(site.serverRelativePath);

const scoreDrive = (drive) => {
  const driveName = normalize(drive.name);
  let lastSegment = '';

  try {
    const driveUrl = new URL(drive.webUrl || '');
    const pathSegments = driveUrl.pathname.split('/').filter(Boolean);
    lastSegment = normalize(pathSegments[pathSegments.length - 1] || '');
  } catch {}

  let score = 0;
  if (driveName === targetLibrary) score = 100;
  if (lastSegment === targetLibrary) score = Math.max(score, 90);
  if (serverRelativePath.includes('/' + driveName + '/')) score = Math.max(score, 80);
  if (serverRelativePath.endsWith('/' + driveName)) score = Math.max(score, 80);

  return score;
};

const ranked = drives
  .map((drive) => ({ drive, score: scoreDrive(drive) }))
  .sort((left, right) => right.score - left.score);

if (!ranked.length || ranked[0].score <= 0) {
  throw new Error(
    'Could not match document library "' +
      site.libraryName +
      '". Available drives: ' +
      drives.map((drive) => drive.name).join(', '),
  );
}

const selected = ranked[0].drive;
return [{
  json: {
    ...site,
    driveId: selected.id,
    driveName: selected.name,
    driveWebUrl: selected.webUrl || '',
  },
}];

const config = $('Config').first().json;
const drive = $('Pick Drive').first().json;
const targetItem = $('Resolve Target Item').first().json;
const pages = $input.all();

const normalizeRoot = (value) => String(value || '')
  .replace(/\\/g, '/')
  .replace(/\/+$/, '');

const downloadRoot = normalizeRoot(config.downloadRoot);
if (!downloadRoot || downloadRoot.startsWith('YOUR_')) {
  throw new Error('Set downloadRoot in the Config node before running the workflow.');
}

const reservedWindowsNames = new Set([
  'CON', 'PRN', 'AUX', 'NUL',
  'COM1', 'COM2', 'COM3', 'COM4', 'COM5', 'COM6', 'COM7', 'COM8', 'COM9',
  'LPT1', 'LPT2', 'LPT3', 'LPT4', 'LPT5', 'LPT6', 'LPT7', 'LPT8', 'LPT9',
]);

const sanitizeSegment = (segment) => {
  let sanitized = String(segment || '')
    .replace(/[<>:"/\\|?*\u0000-\u001F]/g, '_')
    .replace(/[. ]+$/g, '')
    .trim();

  if (!sanitized) sanitized = '_';
  if (reservedWindowsNames.has(sanitized.toUpperCase())) sanitized = '_' + sanitized;
  return sanitized;
};

const joinLocalPath = (root, parts) => [normalizeRoot(root), ...parts].join('/');
const getPageBody = (item) => item.json.body || item.json;

const rawItems = [];
for (const page of pages) {
  const body = getPageBody(page);
  const values = Array.isArray(body.value) ? body.value : [];
  for (const entry of values) {
    if (entry && entry.id) rawItems.push(entry);
  }
}

const lastById = new Map();
for (const item of rawItems) lastById.set(item.id, item);
if (targetItem && targetItem.id && !lastById.has(targetItem.id)) {
  lastById.set(targetItem.id, targetItem);
}

if (targetItem.file) {
  const safeName = sanitizeSegment(targetItem.name || 'downloaded-file');
  return [{
    json: {
      itemId: targetItem.id,
      driveId: drive.driveId,
      relativePath: targetItem.name || safeName,
      targetFilePath: joinLocalPath(downloadRoot, [safeName]),
      sourceWebUrl: targetItem.webUrl || '',
      size: targetItem.size ?? null,
      lastModifiedDateTime: targetItem.lastModifiedDateTime ?? null,
    },
  }];
}

const files = [];

const getRelativeParts = (item) => {
  const parts = [item.name || item.id];
  const visited = new Set([item.id]);
  let parentId = item.parentReference && item.parentReference.id;

  while (parentId) {
    if (parentId === targetItem.id) return parts;
    if (visited.has(parentId)) return null;
    visited.add(parentId);

    const parent = lastById.get(parentId);
    if (!parent) return null;

    parts.unshift(parent.name || parent.id);
    parentId = parent.parentReference && parent.parentReference.id;
  }

  return null;
};

for (const item of lastById.values()) {
  if (!item || !item.id || item.deleted || !item.file) continue;

  const parts = getRelativeParts(item);
  if (!parts || !parts.length) continue;

  const safeParts = parts.map((part) => sanitizeSegment(part));
  files.push({
    json: {
      itemId: item.id,
      driveId: drive.driveId,
      relativePath: parts.join('/'),
      targetFilePath: joinLocalPath(downloadRoot, safeParts),
      sourceWebUrl: item.webUrl || '',
      size: item.size ?? null,
      lastModifiedDateTime: item.lastModifiedDateTime ?? null,
    },
  });
}

files.sort((left, right) => left.json.targetFilePath.localeCompare(right.json.targetFilePath));
return files;
